import{$ as e,A as t,B as n,V as r}from"./chunks/framework.6NwDR3kH.js";var i=JSON.parse(`{"title":"流程","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/色彩管理/流程.md","filePath":"ccc/色彩管理/流程.md"}`),a={name:`ccc/色彩管理/流程.md`};function o(t,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[r(`<h1 id="流程" tabindex="-1">流程 <a class="header-anchor" href="#流程" aria-label="Permalink to “流程”">​</a></h1><p>无特殊说明则以屏幕为目标调色，屏幕观感与原件在约5000K左右光源下观感相似。</p><p>附有转换4000K的LUT，加载后相对更接近4000K光源下观感。</p><p>所谓观感是我主观感受，恐存在巨大偏差。</p><h2 id="扫描v1" tabindex="-1">扫描v1 <a class="header-anchor" href="#扫描v1" aria-label="Permalink to “扫描v1”">​</a></h2><ul><li>扫描仪，中晶i800 plus，银快8，ISO 12641-2色卡校色，正文1000ppi，其余600ppi。</li></ul><p>DxO PhotoLab裁切后保存为360ppi。</p><blockquote><p>屏幕自发光，而印刷品反射光，特性不同，颜色模型是对物理世界的数学模拟，CCD，CMOS对光的响应与人眼不同，不可避免存在偏差。</p></blockquote><p>【屏幕目标】调色，调整影调扩大动态范围。屏幕观感与原件相近，打印观感有偏差。</p><p>【打印目标】调色使打印观感更接近原件，屏幕显示有偏差。</p><blockquote><p>显示器（P3，D65，gamma2.4，100cd），参考光源4000K，5500K。</p></blockquote><h2 id="视频v1" tabindex="-1">视频V1 <a class="header-anchor" href="#视频v1" aria-label="Permalink to “视频V1”">​</a></h2><p>小米12S主摄，4000K光源。</p><h2 id="视频legacy1" tabindex="-1">视频legacy1 <a class="header-anchor" href="#视频legacy1" aria-label="Permalink to “视频legacy1”">​</a></h2><ul><li>小米12S主摄，5500K光源。</li></ul><p>Adobe Camera Raw 配置文件，爱色丽24色卡优化配置。</p><h2 id="压缩格式" tabindex="-1">压缩格式 <a class="header-anchor" href="#压缩格式" aria-label="Permalink to “压缩格式”">​</a></h2><p>libjxl，P3。质量90。360ppi。</p><p>jpegli，sRGB。质量90。360ppi。</p><p>网页上传180ppi，因为浏览器缩图不修改flags用lanczos会出现由印刷网纹引起的明显劣化。</p><blockquote><p>1、jpegli对jpeg鬼影有明显改善，JXL高质量下几乎没有jpeg鬼影。</p><p>2、没有色度抽样，色度抽样会导致高饱和色偏色。</p><p>3、低分辨率高码率相对高分低码，纹理细节保留的更多，而图像轮廓，清晰度，锐度差一些。</p><p>4、180ppi是勉强能打印的下限。</p><p>5、发达国家通过诸如巴塞尔协议等复杂工具，事实上金融殖民，甚至有肆意印钞的特权，而发展中国家超发一点点就会以负面典型进入教材。</p><p>肆意印钞的特权，意味着发达国家所谓FDI投资，事实上用纸去换发展中国家包括资源，劳动附加值在内的实体资产，等资产增值了就套利离场，引发经济动荡，还要蔑称“中等收入陷阱”。</p><p>利用金融工具人为制造通胀通缩，操纵所谓民选，逼迫发展中国家领导陷入出卖国家利益或下台的两难。</p><p>更令人不齿的是，大部分饿殍遍地的发展中国家竟然都是大额农业出口顺差国。</p><p>6、反抗金融霸权并不意味着人民币国际化。目前来看，将99%的人类从金融殖民中解放的将是凯恩斯方案的升级版：金砖币（锚定大宗商品的加权平均价）。</p></blockquote><h3 id="网盘解压密码" tabindex="-1">网盘解压密码 <a class="header-anchor" href="#网盘解压密码" aria-label="Permalink to “网盘解压密码”">​</a></h3><p>一次解压密码（全世界人类联合起来）：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>quanshijierenleilianheqilai</span></span></code></pre></div><p>7z-仅存储</p><p>二次解压密码：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>buxiaozizai.com</span></span></code></pre></div><p>7z-LZMA2-Level9。</p><h2 id="降噪" tabindex="-1">降噪 <a class="header-anchor" href="#降噪" aria-label="Permalink to “降噪”">​</a></h2><p>尝试Topaz Photo AI，DXO Photo Lab，DXO主要队对RAW文件降噪。topaz 1.3.3之前的V1降噪模型会无中生有，锐化也会无中生有。1.3.5后更新的V2beta模型，对印刷网纹降噪后出现横纹。有待进一步测试。</p>`,30)]])}var s=t(a,[[`render`,o]]);export{i as __pageData,s as default};